// Extrae metadatos del correo y detecta adjunto DOCX (formulario F-AF-039)
const msg = $input.first().json;

const subject   = (msg.subject   || msg.Subject   || '').trim();
const fromRaw   = (msg.from      || msg.From      || '').trim();
const fromEmail = fromRaw.match(/<([^>]+)>/) ? fromRaw.match(/<([^>]+)>/)[1] : fromRaw.trim();
const date      = msg.date || msg.Date || new Date().toISOString();
const messageId = msg.id  || msg.messageId || '';
const threadId  = msg.threadId || '';

const attachments = Array.isArray(msg.attachments) ? msg.attachments : [];
const docxAtt = attachments.find(a => {
  const name = (a.name || a.filename || '').toLowerCase();
  return name.endsWith('.docx');
});

const isCandidate = !!docxAtt;

return [{
  json: {
    subject,
    fromRaw,
    fromEmail,
    date,
    messageId,
    threadId,
    isCandidate,
    docxAttachment: docxAtt || null,
  }
}];

// Preserva el contexto del correo y expone datos del adjunto para el nodo de subida
const json = $input.first().json;
const att  = json.docxAttachment || {};

return [{
  json: {
    subject:      json.subject,
    fromRaw:      json.fromRaw,
    fromEmail:    json.fromEmail,
    date:         json.date,
    messageId:    json.messageId,
    threadId:     json.threadId,
    fileName:     att.name || att.filename || 'formulario-F-AF-039.docx',
    attachmentId: att.id   || att.attachmentId || null,
    mimeType:     att.mimeType || 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  }
}];

function safeStr(v) {
  if (v == null) return '';
  if (typeof v === 'string') return v.trim();
  return String(v).trim();
}

const item = $input.first();
const json = item.json || {};

// Metadatos del correo (vienen del Merge final)
const subject     = safeStr(json.subject || json.Subject);
const senderEmail = safeStr(json.fromEmail || json.senderEmail || json.from || json.From || '').replace(/^.*<([^>]+)>.*$/, '$1');
const receivedAt  = safeStr(json.date || json.Date || json.receivedAt);
const googleDocUrl = safeStr(json.googleDocUrl || json.docUrl || json.webViewLink || '');
const fromRaw     = safeStr(json.fromRaw || json.from || json.From || '');
const senderName  = fromRaw.replace(/<[^>]+>/g, '').trim();

// El texto plano exportado llega en 'data' (respuesta text del httpRequest) o en campos del merge
let rawText = safeStr(json.googleDocPlainText || json.plainText || json.data || json.body || json.text || '');

// Si llega en base64 (edge case), decodificar
if (rawText.length > 100 && /^[A-Za-z0-9+/]+=*$/.test(rawText.slice(0, 80))) {
  try { rawText = Buffer.from(rawText, 'base64').toString('utf-8'); } catch (_) {}
}

// Parsear campo etiquetado del formulario
function parseField(text, pattern) {
  const re = new RegExp(pattern + '[:\\s]*([^\n]+)', 'i');
  const m = text.match(re);
  return m ? m[1].trim() : '';
}

const solicitante = parseField(rawText, 'SOLICITANTE') || senderName;
const dependencia = parseField(rawText, 'DEPENDENCIA');
const fecha       = parseField(rawText, 'FECHA');
const motivo      = parseField(rawText, 'MOTIVO|DESCRIPCI[O\u00d3]N|JUSTIFICACI[O\u00d3]N|OBJETO');

// Parsear tabla de activos (columnas separadas por tabs o espacios dobles)
const items = [];
const lines = rawText.split('\n');
let tableStarted = false;

for (const raw of lines) {
  const line = raw.trim();
  if (!line) continue;

  let cols;
  if (line.includes('\t')) {
    cols = line.split('\t').map(c => c.trim());
  } else {
    cols = line.split(/\s{2,}/).map(c => c.trim()).filter(Boolean);
  }

  if (cols.length < 2) continue;

  // Detectar fila de encabezado de la tabla de activos
  if (/PLACA|N[°\u00bao]\.|DESCRIPCI|ART[\u00cdI]CULO|SERIAL|CANTIDAD/i.test(line)) {
    tableStarted = true;
    continue;
  }
  if (!tableStarted) continue;

  const plateRaw  = cols[0] || null;
  const nameRaw   = cols[1] || null;
  const serialRaw = cols[2] || null;
  const qty       = parseInt(cols[3] || '1', 10);
  const quantity  = isNaN(qty) ? 1 : qty;

  if (plateRaw || nameRaw) {
    items.push({ plateRaw, nameRaw, serialRaw, quantity });
  }
}

const sigafPayload = {
  subject,
  senderEmail,
  receivedAt: receivedAt || new Date().toISOString(),
  docxDriveUrl: googleDocUrl,
  rawText,
  formData: { solicitante, dependencia, fecha, motivo },
  items,
};

return [{
  json: {
    sigafPayload,
    _meta: {
      itemsFound:  items.length,
      solicitante,
      dependencia,
      senderEmail,
    }
  }
}];
